tests:
from solution import add
def test_a():
    assert add(2,3)==5
def test_b():
    assert add(-1,1)==0

from solution import softmax
def test_sum():
    assert abs(sum(softmax([1.0,2.0,3.0]))-1.0)<1e-6

from solution import length_of_longest_substring as f
def test_basic():
    assert f('abcabcbb') == 3
def test_all_same():
    assert f('bbbbb') == 1
def test_empty():
    assert f('') == 0
def test_window_no_backtrack():
    assert f('abba') == 2
def test_mixed():
    assert f('pwwkew') == 3

from solution import recall_at_k
def test_full_recall():
    assert recall_at_k(['a','b','c'], ['a','b'], 3) == 1.0
def test_partial_recall():
    assert abs(recall_at_k(['a','x','y'], ['a','b'], 3) - 0.5) < 1e-9
def test_k_truncates():
    assert recall_at_k(['x','a','b'], ['a','b'], 1) == 0.0
def test_empty_relevant_is_zero():
    assert recall_at_k(['a','b'], [], 2) == 0.0
